INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('491', '<p><strong>86. "รัฐกัวเป็นสถานที่ท่องเที่ยวและเยี่ยมชมที่มีนักท่องเที่ยวต่างชาติที่เข้ามาในประเทศอินเดียมากที่สุด โดยมีนักท่องเที่ยวต่างชาติคิดเป็น 40% ของนักท่องเที่ยวต่างชาติทั้งหมดที่มาท่องเที่ยวในประเทศอินเดีย" ข้อใดสอดคล้องกับบทความ</strong></p>', '{"A":"นักท่องเที่ยวที่มาเที่ยวประเทศอินเดีย ส่วนใหญ่มาเที่ยวรัฐกัว","B":"นักท่องเที่ยวทุกคนมาเที่ยวรัฐกัว","C":"นักท่องเที่ยวบางส่วน มาเที่ยวรัฐกัว","D":"นักท่องเที่ยวเกือบทั้งหมดมาเที่ยวรัฐกัว"}', 'C', '<p><strong>ตอบ 3) นักท่องเที่ยวบางส่วน มาเที่ยวรัฐกัว</strong></p><p>จากบทความ นักท่องเที่ยวต่างชาติคิดเป็น 40% ซึ่งยังไม่ถึงครึ่งหนึ่ง จึงใช้คำว่า "ส่วนใหญ่" หรือ "เกือบทั้งหมด" ไม่ได้ ดังนั้นการใช้คำว่านักท่องเที่ยว "บางส่วน" มาเที่ยวรัฐกัว จึงสอดคล้องกับบทความมากที่สุด</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["สรุปความ"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('492', '<p><strong>87. "ก๊าซธรรมชาติเป็นเชื้อเพลิงฟอสซิลที่สะอาดที่สุด เพราะทุกหน่วยพลังงานที่ได้จากก๊าซธรรมชาติทำให้เกิดการแพร่กระจายของคาร์บอนไดออกไซด์เพียงครึ่งหนึ่งของถ่านหินและ 1 ใน 4 ของน้ำมันเท่านั้น นอกจากนี้ ก๊าซธรรมชาติยังปลอดสารกำมะถัน ซึ่งเป็นเหตุให้เกิดฝนกรดเช่นเดียวกับถ่านหินและน้ำมัน" ข้อความใดสรุปได้ถูกต้อง</strong></p>', '{"A":"ก๊าซธรรมชาติทำให้เกิดการแพร่กระจายของคาร์บอนไดออกไซด์สูง","B":"ถ่านหินและน้ำมันเป็นสาเหตุให้เกิดฝนกรด","C":"น้ำมันทำให้เกิดการแพร่กระจายของคาร์บอนไดออกไซด์น้อยกว่าถ่านหิน","D":"ถ่านหินและน้ำมันไม่มีส่วนผสมของสารกำมะถัน"}', 'D', '<p><strong>ตอบ 4) ถ่านหินและน้ำมันไม่มีส่วนผสมของสารกำมะถัน</strong></p><p>จากประโยคสุดท้ายที่ว่า "ก๊าซธรรมชาติยังปลอดสารกำมะถัน ซึ่งเป็นเหตุให้เกิดฝนกรดเช่นเดียวกับถ่านหินและน้ำมัน" ในเฉลยฉบับนี้ตีความหมายว่า ถ่านหินและน้ำมันก็ปลอดสารกำมะถันเช่นกัน จึงตอบข้อ 4</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["สรุปความ"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('493', '<p><strong>88. "ในร่างกายของคนเรามีทั้งเซลล์สร้างเม็ดสีและเซลล์เม็ดเลือดขาว โดยปกติเซลล์เม็ดเลือดขาวมีหน้าที่กำจัดสิ่งแปลกปลอม เช่น เชื้อโรค สารพิษ แต่ด้วยเหตุผลประการที่ยังไม่ทราบแน่ชัด เซลล์เม็ดเลือดขาวมองเห็นเซลล์สร้างเม็ดสีเป็นสิ่งแปลกปลอมจึงกำจัดเซลล์สร้างเม็ดสีซึ่งอยู่ที่ผิวหนัง เกิดเป็นโรคด่างขาว ทำให้ผิวหนังกลายเป็นสีขาวบริเวณกว้างและมีลักษณะเป็นรอยด่างกระจายอยู่ทั่วผิวหนัง" ข้อความข้างต้นกล่าวถึงเรื่องใดเป็นสำคัญ</strong></p>', '{"A":"ความผิดปกติของเซลล์สร้างเม็ดสี","B":"หน้าที่ของเซลล์เม็ดเลือดขาว","C":"กระบวนการเปลี่ยนสีผิว","D":"สาเหตุของโรคด่างขาว"}', 'D', '<p><strong>ตอบ 4) สาเหตุของโรคด่างขาว</strong></p><p>สังเกตบทความทั้งหมด พูดถึงหน้าที่ของเซลล์และความบกพร่องที่เกิดขึ้น สุดท้ายจึงสรุปว่าทำให้เกิดโรคด่างขาวและอธิบายลักษณะโรคเพิ่มเติม ดังนั้นสาระสำคัญคือการอธิบายสาเหตุของโรคด่างขาว</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["สรุปความ"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('494', '<p><strong>89. "คนไทยรู้จักการนำทรัพยากรธรรมชาติที่ผูกพันกับวิถีท้องถิ่นยาวนานมาทำให้เกิดคุณค่าและงานชิ้นใหม่ เช่น การนำไม้ไผ่มาทำพื้นบ้าน ฝาบ้าน และรั้วบ้านอย่างสวยงาม สะท้อนวิถีชีวิตแบบตะวันออกได้อย่างนุ่มนวล ในขณะที่เหล็ก หิน คอนกรีต ยิ่งใช้ยิ่งหมดไป การใช้ไม้ไผ่ซึ่งเป็นพืชที่ปลูกทดแทนได้เร็วน่าจะเป็นทางเลือกที่ดีกว่า" ข้อความใดไม่สอดคล้องกับข้อความข้างต้น</strong></p>', '{"A":"ข้อดีของการใช้ไม้ไผ่คือการประหยัดค่าใช้จ่าย","B":"ไม้ไผ่เป็นวัสดุที่คนไทยคุ้นเคยมานาน","C":"เราควรหาวัสดุทดแทนเพื่อใช้ในการก่อสร้าง","D":"วัสดุที่ใช้ในการก่อสร้างบ่งบอกถึงวัฒนธรรมได้"}', 'A', '<p><strong>ตอบ 1) ข้อดีของการใช้ไม้ไผ่คือการประหยัดค่าใช้จ่าย</strong></p><p>บทความไม่ได้พูดถึงการประหยัดหรือเรื่องของค่าใช้จ่ายในการก่อสร้างเลย แต่เน้นพูดถึงการเปรียบเทียบวัสดุและการปลูกทดแทนเป็นหลัก ดังนั้นข้อ 1 จึงไม่สอดคล้อง</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["สรุปความ"]', '2559');
INSERT INTO questions (id, question_text, choices, correct_answer, explanation, category, subject, difficulty, is_custom, created_at, updated_at, catalogs, exam_year) VALUES ('495', '<p><strong>90. จากข้อความต่อไปนี้ ข้อใดเรียงลำดับได้ถูกต้อง</strong></p><p>1) เพเนียด หมายถึง วงล้อมทำเป็นคอกสำหรับคล้องช้าง มี 2 ชั้น คือเพเนียดใหญ่และเพเนียดเล็ก<br/>2) ต่อมาใช้พลายเข้าขนาบ 2 ข้าง บังคับให้ช้างป่าเข้าซองในไปเพเนียดเล็ก<br/>3) เพเนียดใหญ่อยู่ชั้นนอก ทำด้วยซุงต้นใหญ่ เรียกว่า เสาตะลุง<br/>4) การคล้องช้างจะมีช้างพังเป็นช้างต่อล่อให้ช้างป่าติดตามเข้าไปในเพเนียดใหญ่</p>', '{"A":"1 - 2 - 3 - 4","B":"1 - 3 - 4 - 2","C":"1 - 4 - 2 - 3","D":"3 - 1 - 4 - 2"}', 'B', '<p><strong>ตอบ 2) 1 - 3 - 4 - 2</strong></p><p>เรียบเรียงเป็นบทความได้ ดังนี้<br/>เพเนียด หมายถึง วงล้อมทำเป็นคอกสำหรับคล้องช้าง มี 2 ชั้น คือเพเนียดใหญ่และเพเนียดเล็ก (1)<br/>เพเนียดใหญ่อยู่ชั้นนอก ทำด้วยซุงต้นใหญ่ เรียกว่า เสาตะลุง (3)<br/>การคล้องช้างจะมีช้างพังเป็นช้างต่อล่อให้ช้างป่าติดตามเข้าไปในเพเนียดใหญ่ (4)<br/>ต่อมาใช้พลายเข้าขนาบ 2 ข้าง บังคับให้ช้างป่าเข้าซองในไปเพเนียดเล็ก (2)</p>', 'ก.พ.', 'ความรู้ความสามารถทั่วไป', 50, 0, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP, '["เรียงประโยค"]', '2559');
